import { AlertCircle, Loader2 } from 'lucide-react';

import { HarmonyDialog } from '@/components/ui/harmony-dialog';
import { PermissionGate } from '@/components/shared/PermissionGate';
import { PERMISSIONS } from '@/constants/permissions';
import HarmonyForm from '@/components/forms/HarmonyForm';
import type { Role } from '@/types/role';
import { Button } from '@/shadcn/components/ui/button';
import { Alert, AlertDescription } from '@/shadcn/components/ui/alert';

interface RoleFormDialogProps {
  open: boolean;
  onClose: () => void;
  editingRole: Role | null;
  onSubmit: (formData: any) => void;
  error: string | null;
  isSubmitting: boolean;
}

export function RoleFormDialog({
  open,
  onClose,
  editingRole,
  onSubmit,
  error,
  isSubmitting,
}: RoleFormDialogProps) {
  return (
    <HarmonyDialog
      open={open}
      onOpenChange={(o) => { if (!o) onClose(); }}
      title={editingRole ? 'Update Role' : 'Create Role'}
      footerChildren={
        <div className="flex justify-end gap-3 w-full">
          <Button type="button" variant="outline" onClick={onClose} disabled={isSubmitting}>
            Cancel
          </Button>
          <PermissionGate
            permission={editingRole ? PERMISSIONS.Role.Update : PERMISSIONS.Role.Create}
            mode="disable"
          >
            <Button
              type="button"
              disabled={isSubmitting}
              onClick={() => document.querySelector("form")?.requestSubmit?.()}
            >
              {isSubmitting ? <Loader2 className="animate-spin" size={16} /> : null}
              {editingRole ? 'Update Role' : 'Create Role'}
            </Button>
          </PermissionGate>
        </div>
      }
    >
      {error && (
        <Alert variant="destructive">
          <AlertCircle />
          <AlertDescription>{error}</AlertDescription>
        </Alert>
      )}
      <HarmonyForm
        dtoName={editingRole ? "UpdateRoleDTO" : "CreateRoleDTO"}
        mode={editingRole ? "edit" : "create"}
        initialValues={editingRole ? { Description: editingRole.description, Active: editingRole.active } : undefined}
        onSubmit={onSubmit}
        isPending={isSubmitting}
        hideSubmitButton
      />
    </HarmonyDialog>
  );
}
